VALUES
  ('social-worker-moex-05390', 'social-worker', 'social-worker-moex-106-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '依上文，下列何者不是工之僑改變桐琴的方法？', '["仿造斑剝木質紋理", "摹寫古文字體款識", "掩埋增加樸拙色調", "聘請巧匠雕金鏤玉"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "380a9c199eb9", "answer_pdf_sha1": "0725574887ca", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05391', 'social-worker', 'social-worker-moex-106-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '承上題，工之僑之所以感歎，是因為：', '["國工貪賄成習，妒賢嫉才", "世人貴古賤今，向聲背實", "世風窮奢極侈，注重享受", "世人譁眾取寵，迷失本心"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "380a9c199eb9", "answer_pdf_sha1": "0725574887ca", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05392', 'social-worker', 'social-worker-moex-106-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '陶淵明〈移居〉云：「昔欲居南村，非為卜其宅。聞多素心人，樂與數晨夕。懷此 頗有年，今日從茲役。敝廬何必廣，取足蔽床席。鄰曲時時來，抗言談在昔。奇文 共欣賞，疑義相與析。」從此詩看來，陶淵明之所以想要移居南村的主要原因為何？', '["有現成屋舍可以居住", "有很多有學問的朋友", "經占卜顯示適宜居住", "有很多心地真純之人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "380a9c199eb9", "answer_pdf_sha1": "0725574887ca", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05393', 'social-worker', 'social-worker-moex-106-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「頃歲孫莘老識歐陽文忠公，嘗乘閒以文字問之，云：『無它術，唯勤讀書而多為 之，自工。世人患作文字少，又嬾讀書，每一篇出，即求過人，如此少有至者。疵 病不必待人指擿，多作自能見之。』此公以其嘗試者告人，故尤有味。」 有關上引文字意涵的敘述，下列選項正確的是：', '["勤讀多寫，文章自工", "古之學者為己，今之學者為人", "「患作文字少」，意謂惟恐作文太少", "「每一篇出，即求過人」，意謂不恥下問"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "380a9c199eb9", "answer_pdf_sha1": "0725574887ca", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05394', 'social-worker', 'social-worker-moex-106-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「『雅舍』非我所有，我僅是房客之一。但思『          』，人生本來如寄，我 住『雅舍』一日，『雅舍』即一日為我所有。即使此一日亦不能算是我有，至少此 一日『雅舍』所能給予之苦辣酸甜，我實躬受親嘗。」 以上引文中的空格，最適合填入的選項是：', '["天地者，萬物之逆旅", "生也死之徒，死也生之始", "安時而處順，哀樂不能入也", "心似已灰之木，身如不繫之舟"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "380a9c199eb9", "answer_pdf_sha1": "0725574887ca", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05395', 'social-worker', 'social-worker-moex-106-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '歇後語的設計，常以古人的著名故事為基礎，例如「姜太公釣魚－－願者上鈎」。', '["劉備摔孩子、", "關公走麥城、", "龐統當知縣、", "徐庶進 曹營，都是三國人物的故事，其對應的後半依序應是："]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "380a9c199eb9", "answer_pdf_sha1": "0725574887ca", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05396', 'social-worker', 'social-worker-moex-106-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '《老子》：「上士聞道，勤而行之；中士聞道，若存若亡；下士聞道，大笑之。不 笑，不足以為道。」 下列敘述，符合上文旨意的選項是：', '["道，原非所有人盡能體悟", "道，其實是欺矇世人的幌子", "智者常迷於道，愚者反能悟道", "君子能欺以其方，難罔以非其道"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "380a9c199eb9", "answer_pdf_sha1": "0725574887ca", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05397', 'social-worker', 'social-worker-moex-106-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '《史記．殷本紀》：「湯出，見野張網四面，祝曰：『自天下四方皆入吾網。』湯 曰：『嘻，盡之矣。』乃去其三面，祝曰：『欲左，左；欲右，右。不用命，乃入 吾網。』諸侯聞之，曰：『湯德至矣，及禽獸。』」 關於這段文字的內容，下列選項何者最為正確？', '["商湯祝願天下四方諸侯皆朝宗於己", "商湯狩獵時，命令左右採取三驅之法", "商湯狩獵時，具有不一網打盡的仁德之心", "商湯認為狩獵雖是殺戮之舉，也必須維護生態平衡"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "380a9c199eb9", "answer_pdf_sha1": "0725574887ca", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05398', 'social-worker', 'social-worker-moex-106-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列詞句沒有呈現出時間意象的是：', '["楊柳岸，曉風殘月", "斜陽正在，煙柳斷腸處", "低聲問向誰行宿，城上已三更", "問君能有幾多愁，恰似一江春水向東流"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "380a9c199eb9", "answer_pdf_sha1": "0725574887ca", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05399', 'social-worker', 'social-worker-moex-106-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '閱讀下列詩篇，選出敘述正確的選項： 甲、一擊車中膽氣高，祖龍社稷已驚搖。如何十二金人外，猶有民間鐵未銷。 （陳孚〈博浪沙〉） 乙、竹帛煙銷帝業虛，關河空鎖祖龍居。坑灰未冷山東亂，劉項原來不讀書。 （章碣〈焚書坑〉）', '["甲詩認為意氣用事的刺殺無法推翻秦朝", "乙詩譴責劉邦和項羽俱為不學無術之徒", "二詩皆指出過度箝制無法防止秦朝覆亡", "二詩皆因尋訪古蹟觸發歷史興衰的感慨"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "380a9c199eb9", "answer_pdf_sha1": "0725574887ca", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
